const getIconForCategory = (title) => {
  const t = (title || "").toLowerCase();
  if (t.includes("medicine")) return "💊";
  if (t.includes("care") || t.includes("baby")) return "🍼";
  if (t.includes("supplement") || t.includes("vitamin")) return "🧪";
  if (t.includes("equipment") || t.includes("monitor")) return "🩺";
  if (t.includes("diagnostic")) return "🔬";
  return "📦";
};

function Shop() {
  const navigate = useNavigate();
  const { id } = useParams();
  const { data } = useContext(DataContext);
  const location = useLocation();
  const dispatch = useDispatch();
  const queryParams = useQuery();

  const [minPrice, setMinPrice] = useState(0);
  const [maxPrice, setMaxPrice] = useState(0);
  const [query, setQuery] = useState("");
  const [filteredData, setFilteredData] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const [sortOrder, setSortOrder] = useState("latest");
  const [viewMode, setViewMode] = useState("grid");
  const [activeCategory, setActiveCategory] = useState("All");
  const [activeBrand, setActiveBrand] = useState("All");
  const [isMobileSidebarOpen, setIsMobileSidebarOpen] = useState(false);
  const [subcats, setSubcats] = useState([]);
  const [cats, setCats] = useState([]);
  const [expandedCat, setExpandedCat] = useState(null);

  const { product } = useSelector((state) => state.product);
  const addedToWish = useSelector(selectWishlist);
  const subcategoryParam = queryParams.get("subcategory");
  const categoryParam = queryParams.get("category");
  const tagParam = queryParams.get("tag");

  const productsPerPage = 12;

  useEffect(() => {
    const params = new URLSearchParams(location.search);
    const catParam = params.get("category");
    const subParam = params.get("subcategory");

    if (catParam) {
      setActiveCategory(catParam);
      // Auto-expand the matching category in the sidebar if we find it by title
      const matchedCat = cats.find((c) => c.title === catParam);
      if (matchedCat) setExpandedCat(matchedCat._id);
    } else if (!subParam) {
      setActiveCategory("All");
      setExpandedCat(null);
    }
  }, [location.search, cats]);

  // Real-time categories and subcategories from DB
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [cRes, sRes] = await Promise.all([
          axios.get(`${base_url}category`),
          axios.get(`${base_url}subcategory`),
        ]);
        setCats(Array.isArray(cRes.data) ? cRes.data : []);
        setSubcats(Array.isArray(sRes.data) ? sRes.data : []);
      } catch (e) {
        console.error("Fetch metadata err", e);
      }
    };
    fetchData();
  }, []);

  useEffect(() => {
    dispatch(getAllProducts());
  }, [dispatch]);

  const uniqueCategories = useMemo(() => {
    return ["All", ...new Set(product.map((p) => p.category).filter(Boolean))];
  }, [product]);

  const uniqueBrands = useMemo(() => {
    return ["All", ...new Set(product.map((p) => p.brand).filter(Boolean))];
  }, [product]);

  const filterAndSort = useMemo(() => {
    let result = [...(data || [])];
    const lcQuery = query.toLowerCase();

    result = result.filter((p) => {
      const pPrice = parseInt(p.price) || 0;
      const matchPrice =
        (minPrice === 0 || pPrice >= minPrice) &&
        (maxPrice === 0 || pPrice <= maxPrice);
      const matchQ =
        p.title.toLowerCase().includes(lcQuery) ||
        p.subcategory?.toLowerCase().includes(lcQuery);
      const matchTag = tagParam
        ? p.tags?.some((t) => t.toLowerCase() === tagParam.toLowerCase())
        : true;

      // Robust Category Match
      let matchCat = activeCategory === "All";
      if (!matchCat) {
        const cleanTarget = activeCategory
          .toLowerCase()
          .trim()
          .replace(/['"]+$/, "");
        const pCat = (p.category || "")
          .toLowerCase()
          .trim()
          .replace(/['"]+$/, "");
        matchCat = pCat === cleanTarget;
      }

      const matchBrand = activeBrand === "All" || p.brand === activeBrand;

      // Robust Subcategory Match
      let matchSub = !subcategoryParam;
      if (!matchSub) {
        const cleanSubTarget = subcategoryParam.toLowerCase().trim();
        const pSub = (p.subcategory || "").toLowerCase().trim();
        matchSub = pSub === cleanSubTarget;
      }

      return (
        matchPrice && matchQ && matchTag && matchCat && matchBrand && matchSub
      );
    });

    if (sortOrder === "latest")
      result.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
    else if (sortOrder === "oldest")
      result.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
    else if (sortOrder === "priceLow")
      result.sort(
        (a, b) => (parseInt(a.price) || 0) - (parseInt(b.price) || 0),
      );
    else if (sortOrder === "priceHigh")
      result.sort(
        (a, b) => (parseInt(b.price) || 0) - (parseInt(a.price) || 0),
      );

    return result;
  }, [
    data,
    query,
    minPrice,
    maxPrice,
    activeCategory,
    activeBrand,
    tagParam,
    subcategoryParam,
    sortOrder,
  ]);

  const totalPages = Math.ceil(filterAndSort.length / productsPerPage);
  const currentProducts = filterAndSort.slice(
    (currentPage - 1) * productsPerPage,
    currentPage * productsPerPage,
  );

  const handleWishlist = (pid) => dispatch(addToWishlist(pid, navigate, 1));

  return (
    <>
      <style>{SHOP_STYLES}</style>
      <main className="sp-page">
        <HomeAds />

        {/* Mobile Overlay Backdrop */}
        <div
          className={`sp-overlay${isMobileSidebarOpen ? " open" : ""}`}
          onClick={() => setIsMobileSidebarOpen(false)}
        />

        <div className="sp-layout">
          {/* ── SIDEBAR ── */}
          <aside className={`sp-sidebar ${isMobileSidebarOpen ? "open" : ""}`}>
            <button
              className="sp-sidebar__close"
              onClick={() => setIsMobileSidebarOpen(false)}
            >
              ✕
            </button>

            {/* Registry Search */}
            <div className="sp-widget">
              <div className="sp-widget__head">
                <h3 className="sp-widget__title">Registry Search</h3>
                <div className="sp-widget__icon">
                  <svg
                    width="14"
                    height="14"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2.5"
                  >
                    <circle cx="11" cy="11" r="8" />
                    <path d="m21 21-4.3-4.3" />
                  </svg>
                </div>
              </div>
              <input
                type="text"
                placeholder="Clinical term or product..."
                className="sp-search-field"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
              />
            </div>

            {/* Categorization Tree */}
            <div className="sp-widget">
              <div className="sp-widget__head">
                <h3 className="sp-widget__title">Categorization</h3>
                <div className="sp-widget__icon">
                  <svg
                    width="14"
                    height="14"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2.5"
                  >
                    <rect width="7" height="7" x="3" y="3" rx="1" />
                    <rect width="7" height="7" x="14" y="3" rx="1" />
                    <rect width="7" height="7" x="14" y="14" rx="1" />
                    <rect width="7" height="7" x="3" y="14" rx="1" />
                  </svg>
                </div>
              </div>
              <ul className="sp-list">
                <li className="sp-list__item">
                  <button
                    className={`sp-list__btn ${activeCategory === "All" ? "active" : ""}`}
                    onClick={() => {
                      setActiveCategory("All");
                      setExpandedCat(null);
                      navigate("/shop");
                    }}
                  >
                    <span>Pulse Clinical Catalog</span>
                    <span className="sp-list__count">{product.length}</span>
                  </button>
                </li>
                {cats.map((c) => {
                  const subCount = subcats.filter((s) => {
                    const target = c.title
                      .toLowerCase()
                      .trim()
                      .replace(/['"]+$/, "");
                    const sCatTitle =
                      typeof s.category === "object"
                        ? s.category.title
                        : s.parentCategory || s.category;
                    return (
                      sCatTitle &&
                      typeof sCatTitle === "string" &&
                      sCatTitle
                        .toLowerCase()
                        .trim()
                        .replace(/['"]+$/, "") === target
                    );
                  }).length;
                  const isActive = activeCategory === c.title;
                  const isExpanded = expandedCat === c._id;

                  return (
                    <li key={c._id} className="sp-list__item">
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          width: "100%",
                          gap: 6,
                          marginBottom: 2,
                        }}
                      >
                        <button
                          className={`sp-list__btn ${isActive ? "active" : ""}`}
                          style={{ flex: 1 }}
                          onClick={() => {
                            setActiveCategory(c.title);
                            setExpandedCat(isExpanded ? null : c._id);
                          }}
                        >
                          <span
                            style={{
                              display: "flex",
                              alignItems: "center",
                              gap: 8,
                            }}
                          >
                            <span style={{ fontSize: "14px", opacity: 0.7 }}>
                              {getIconForCategory(c.title)}
                            </span>
                            {c.title}
                          </span>
                          <span className="sp-list__count">
                            {
                              product.filter((p) => p.category === c.title)
                                .length
                            }
                          </span>
                        </button>
                        {subCount > 0 && (
                          <button
                            className="sp-tree-toggle"
                            onClick={(e) => {
                              e.stopPropagation();
                              setExpandedCat(isExpanded ? null : c._id);
                            }}
                            aria-label="Toggle subcategories"
                          >
                            {isExpanded ? "−" : "+"}
                          </button>
                        )}
                      </div>

                      {isExpanded && (
                        <ul
                          className="sp-list"
                          style={{
                            paddingLeft: 18,
                            marginTop: 4,
                            marginBottom: 10,
                            display: "flex",
                            flexDirection: "column",
                            gap: 2,
                          }}
                        >
                          {subcats
                            .filter((s) => {
                              const target = c.title
                                .toLowerCase()
                                .trim()
                                .replace(/['"]+$/, "");
                              const sCatTitle =
                                typeof s.category === "object"
                                  ? s.category.title
                                  : s.parentCategory || s.category;
                              return (
                                sCatTitle &&
                                typeof sCatTitle === "string" &&
                                sCatTitle
                                  .toLowerCase()
                                  .trim()
                                  .replace(/['"]+$/, "") === target
                              );
                            })
                            .map((sc) => (
                              <li key={sc._id}>
                                <button
                                  onClick={() =>
                                    navigate(
                                      `/shop?subcategory=${encodeURIComponent(sc.title)}&category=${encodeURIComponent(c.title)}`,
                                    )
                                  }
                                  className={`sp-list__btn ${subcategoryParam === sc.title ? "active" : ""}`}
                                  style={{
                                    padding: "8px 12px",
                                    fontSize: "12.5px",
                                    fontWeight: 650,
                                    color: "#64748b",
                                  }}
                                >
                                  <span>{sc.title}</span>
                                </button>
                              </li>
                            ))}
                        </ul>
                      )}
                    </li>
                  );
                })}
              </ul>
            </div>

            {/* Price Filtration */}
            <div className="sp-widget">
              <div className="sp-widget__head">
                <h3 className="sp-widget__title">Price Filtration</h3>
                <div className="sp-widget__icon">
                  <svg
                    width="14"
                    height="14"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="currentColor"
                    strokeWidth="2.5"
                  >
                    <path d="M12 2v20M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6" />
                  </svg>
                </div>
              </div>
              <div className="sp-price-row">
                <input
                  type="number"
                  className="sp-price-input"
                  placeholder="Min"
                  value={minPrice || ""}
                  onChange={(e) => setMinPrice(Number(e.target.value))}
                />
                <input
                  type="number"
                  className="sp-price-input"
                  placeholder="Max"
                  value={maxPrice || ""}
                  onChange={(e) => setMaxPrice(Number(e.target.value))}
                />
              </div>
            </div>
          </aside>

          <div className="sp-main">
            {/* Hero Section removed per user request */}

            {/* Real-time Subcategory Image Bar moved inside */}
            <div
              className="sp-cats-bar"
              style={{
                border: "none",
                background: "transparent",
                marginBottom: 24,
              }}
            >
              <div
                className="sp-cats-inner"
                style={{ padding: 0, justifyContent: "flex-start" }}
              >
                <div
                  className={`sp-cat-link ${!subcategoryParam ? "active" : ""}`}
                  onClick={() =>
                    navigate(
                      categoryParam
                        ? `/shop?category=${categoryParam}`
                        : "/shop",
                    )
                  }
                >
                  <div className="sp-cat-img-box">
                    {getIconForCategory(categoryParam)}
                  </div>
                  <span className="sp-cat-label">
                    {categoryParam || "All Items"}
                  </span>
                </div>
                {subcats
                  .filter((s) => {
                    if (!categoryParam) return true;
                    const target = categoryParam
                      .toLowerCase()
                      .trim()
                      .replace(/['"]+$/, "");

                    const isLinkedByProduct = product.some(
                      (p) =>
                        (p.category || "")
                          .toLowerCase()
                          .trim()
                          .replace(/['"]+$/, "") === target &&
                        (p.subcategory || "").toLowerCase().trim() ===
                          (s.title || "").toLowerCase().trim(),
                    );
                    if (isLinkedByProduct) return true;

                    const sCatTitle =
                      typeof s.category === "object"
                        ? s.category.title
                        : s.parentCategory || s.category;
                    if (
                      sCatTitle &&
                      typeof sCatTitle === "string" &&
                      sCatTitle
                        .toLowerCase()
                        .trim()
                        .replace(/['"]+$/, "") === target
                    )
                      return true;
                    return false;
                  })
                  .map((s) => {
                    const img =
                      s.images?.[0]?.secure_url || s.image?.[0]?.secure_url;
                    return (
                      <div
                        key={s._id}
                        className={`sp-cat-link ${subcategoryParam === s.title ? "active" : ""}`}
                        onClick={() =>
                          navigate(
                            `/shop?subcategory=${encodeURIComponent(s.title)}${categoryParam ? `&category=${categoryParam}` : ""}`,
                          )
                        }
                      >
                        <div className="sp-cat-img-box">
                          {img ? (
                            <img src={img} alt={s.title} />
                          ) : (
                            <span>{getIconForCategory(s.title)}</span>
                          )}
                        </div>
                        <span className="sp-cat-label">{s.title}</span>
                      </div>
                    );
                  })}
              </div>
            </div>

            {/* STICKY TOOLBAR moved inside sp-main to stick within the right column if needed */}
            <div className="sp-sticky-wrap">
              <div className="sp-sticky-inner">
                <div className="sp-sticky-left">
                  <div className="sp-sticky-label">
                    <span>📦</span>{" "}
                    {categoryParam || subcategoryParam || "All Products"}
                    <small
                      style={{
                        marginLeft: 6,
                        color: "#94a3b8",
                        fontWeight: 600,
                      }}
                    >
                      ({filterAndSort.length})
                    </small>
                  </div>
                </div>

                <div className="sp-controls">
                  <button
                    className="sp-filter-btn"
                    onClick={() => setIsMobileSidebarOpen(true)}
                  >
                    <svg
                      width="14"
                      height="14"
                      viewBox="0 0 24 24"
                      fill="none"
                      stroke="currentColor"
                      strokeWidth="3"
                    >
                      <path d="M4 6h16M4 12h16M4 18h7" />
                    </svg>
                    FILTER
                  </button>
                  <div
                    style={{ display: "flex", alignItems: "center", gap: 8 }}
                  >
                    <span
                      style={{
                        fontSize: 11,
                        fontWeight: 800,
                        color: "#94a3b8",
                        textTransform: "uppercase",
                      }}
                    >
                      Sort:
                    </span>
                    <select
                      className="sp-sort-select"
                      value={sortOrder}
                      onChange={(e) => setSortOrder(e.target.value)}
                    >
                      <option value="latest">Newest</option>
                      <option value="priceLow">Price Low</option>
                      <option value="priceHigh">Price High</option>
                    </select>
                  </div>
                  <div
                    className="sp-view-toggle"
                    style={{ display: "flex", gap: 4 }}
                  >
                    <button
                      className={`sp-view-btn ${viewMode === "grid" ? "active" : ""}`}
                      onClick={() => setViewMode("grid")}
                    >
                      <svg
                        width="14"
                        height="14"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="3"
                      >
                        <rect width="7" height="7" x="3" y="3" rx="1" />
                        <rect width="7" height="7" x="14" y="3" rx="1" />
                        <rect width="7" height="7" x="14" y="14" rx="1" />
                        <rect width="7" height="7" x="3" y="14" rx="1" />
                      </svg>
                    </button>
                    <button
                      className={`sp-view-btn ${viewMode === "list" ? "active" : ""}`}
                      onClick={() => setViewMode("list")}
                    >
                      <svg
                        width="14"
                        height="14"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="3"
                      >
                        <line x1="8" y1="6" x2="21" y2="6" />
                        <line x1="8" y1="12" x2="21" y2="12" />
                        <line x1="8" y1="18" x2="21" y2="18" />
                        <line x1="3" y1="6" x2="3.01" y2="6" />
                        <line x1="3" y1="12" x2="3.01" y2="12" />
                        <line x1="3" y1="18" x2="3.01" y2="18" />
                      </svg>
                    </button>
                  </div>
                </div>
              </div>
            </div>

            {currentProducts.length === 0 ? (
              <div className="sp-empty">
                <div className="sp-empty__icon">🔬</div>
                <h3 className="sp-empty__title">No matching inventory</h3>
                <p className="sp-empty__text">
                  Adjust your filters or try a different clinical term.
                </p>
              </div>
            ) : viewMode === "grid" ? (
              <div className="sp-grid">
                {currentProducts.map((p) => (
                  <article
                    className="sp-card"
                    key={p._id}
                    onClick={() => navigate(`/productdetails/${p._id}`)}
                    role="article"
                    aria-label={p.title}
                  >
                    <div className="sp-card__img-wrap">
                      <img
                        className="sp-card__img"
                        src={p?.colors[0]?.images[0]?.secure_url}
                        alt={p.title}
                        loading="lazy"
                      />
                    </div>
                    <div className="sp-card__body">
                      <span className="sp-card__cat">{p.category}</span>
                      <h3 className="sp-card__title">{p.title}</h3>
                      <div style={{ marginTop: "auto", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                        <span className="sp-card__price">{p.price?.toLocaleString()} ETB</span>
                        <button
                          onClick={(e) => { e.stopPropagation(); handleWishlist(p._id); }}
                          aria-label="Wishlist"
                          style={{ border: "none", background: "none", color: addedToWish.some((w) => w._id === p._id) ? "#ef4444" : "#cbd5e1", cursor: "pointer" }}
                        >
                          {addedToWish.some((w) => w._id === p._id) ? <AiFillHeart size={20} /> : <AiOutlineHeart size={20} />}
                        </button>
                      </div>
                    </div>
                  </article>
                ))}
              </div>
            ) : (
              <div className="sp-list-view">
                {currentProducts.map((p) => (
                  <div
                    key={p._id}
                    className="sp-list-item"
                    onClick={() => navigate(`/productdetails/${p._id}`)}
                    role="article"
                    aria-label={p.title}
                  >
                    <img
                      className="sp-list-item__img"
                      src={p?.colors[0]?.images[0]?.secure_url}
                      alt={p.title}
                      loading="lazy"
                    />
                    <div className="sp-list-item__body">
                      <span className="sp-list-item__cat">{p.category}</span>
                      <h3 className="sp-list-item__title">{p.title}</h3>
                      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                        <span className="sp-list-item__price">{p.price?.toLocaleString()} ETB</span>
                        <button
                          onClick={(e) => { e.stopPropagation(); handleWishlist(p._id); }}
                          aria-label="Wishlist"
                          style={{ border: "none", background: "none", color: addedToWish.some((w) => w._id === p._id) ? "#ef4444" : "#cbd5e1", cursor: "pointer" }}
                        >
                          {addedToWish.some((w) => w._id === p._id) ? <AiFillHeart size={18} /> : <AiOutlineHeart size={18} />}
                        </button>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}

            {/* Pagination */}
            {totalPages > 1 && (
              <div className="sp-pager">
                <button
                  className="sp-pager__btn"
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage((c) => c - 1)}
                >
                  Prev
                </button>
                {Array.from({ length: totalPages }).map((_, i) => (
                  <button
                    key={i}
                    className={`sp-pager__btn ${currentPage === i + 1 ? "active" : ""}`}
                    onClick={() => setCurrentPage(i + 1)}
                  >
                    {i + 1}
                  </button>
                ))}
                <button
                  className="sp-pager__btn"
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage((c) => c + 1)}
                >
                  Next
                </button>
              </div>
            )}
          </div>
        </div>

        <Footer />
      </main>
    </>
  );
}

export default Shop;
